// components/PrevArrow.jsx
import React from 'react';
import styles from './HeroSection.module.css'; // Импортируем стили

function PrevArrow(props) {
  const { className, style, onClick } = props;
  return (
    <button
      className={className}
      onClick={onClick}
      style={{ ...style, ...{
        display: "block",
        background: 'transparent', // Прозрачный фон
        border: '2px solid #ff7a00', // Оранжевая рамка
        borderRadius: "50%", // Круглый
        width: "30px",
        height: "30px",
        left: "-30px", // Позиционирование слева
        top: "50%",
        transform: "translateY(-50%)",
        cursor: "pointer",
        outline: "none", // Убираем обводку при фокусе
        // Добавляем иконку (стрелку влево)
        position: 'relative',
      } }}
    >
      <span style={{
        position: 'absolute',
        top: '50%',
        left: '50%',
        transform: 'translate(-60%, -50%)',
        fontSize: '16px',
        color: '#ff7a00',
      }}>&#8249;</span> {/* Стрелка влево */}
    </button>
  );
}

export default PrevArrow;
